import{_ as o,o as t,c as r,ae as s}from"./chunks/framework.DHedrh8w.js";const a="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330104754.BCTVNwFQ.png",c="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330105439.BezzOBGx.png",n="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330105610.E7GBHvN6.png",l="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330105708.Cjk1KRNt.png",i="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330105743.Bjar7luz.png",p="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330110935.4yLfZcTN.png",d="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330111006.Ci35xFAy.png",m="/x-lab/assets/QQ%E6%88%AA%E5%9B%BE20260330111102.oS4pltYH.png",f=JSON.parse('{"title":"操作记录与演示指南","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/operation-records/README.md","filePath":"tutorials/operation-records/README.md"}'),h={name:"tutorials/operation-records/README.md"};function g(E,e,_,u,b,B){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="操作记录与演示指南" tabindex="-1">操作记录与演示指南 <a class="header-anchor" href="#操作记录与演示指南" aria-label="Permalink to &quot;操作记录与演示指南&quot;">​</a></h1><p>这份文档结合我们提供的 <a href="./../../demo.html"><code>demo</code></a> 示例和您实际测试生成的 <a href="./../../practice.html"><code>practice</code></a> 插件，详细演示了 Chrome 插件从开发、安装到实操使用的全流程记录。</p><p>代码仓库地址：<a href="https://github.com/yunquna/chromeextdemo" target="_blank" rel="noreferrer">https://github.com/yunquna/chromeextdemo</a></p><p>幻灯片地址：<a href="https://docs.google.com/presentation/d/1C4R3fGoNyp8jGjcE6TbyYkgnBz4h49OWB-XeUNh5zfs/edit?usp=sharing" target="_blank" rel="noreferrer">https://docs.google.com/presentation/d/1C4R3fGoNyp8jGjcE6TbyYkgnBz4h49OWB-XeUNh5zfs/edit?usp=sharing</a></p><hr><h2 id="🛠️-第一步-实操开发-开发" tabindex="-1">🛠️ 第一步：实操开发 (开发) <a class="header-anchor" href="#🛠️-第一步-实操开发-开发" aria-label="Permalink to &quot;🛠️ 第一步：实操开发 (开发)&quot;">​</a></h2><p>在实际开发中，我们可以利用预设的提示词（Tech Prompt）指导大语言模型（如 Claude 或 Gemini）为我们快速生成基础的插件脚本。这其中包括了清单文件 <code>manifest.json</code>、逻辑脚本 <code>content.js</code> 以及样式表 <code>content.css</code>。</p><p><img src="'+a+'" alt="开发提示词与代码生成"></p><hr><h2 id="🧩-第二步-安装与载入插件-安装" tabindex="-1">🧩 第二步：安装与载入插件 (安装) <a class="header-anchor" href="#🧩-第二步-安装与载入插件-安装" aria-label="Permalink to &quot;🧩 第二步：安装与载入插件 (安装)&quot;">​</a></h2><p>在代码开发完成后，插件是以文件夹的形式存在的（如项目中的 <code>practice/table-exporter/</code>）。我们需要将其载入到 Chrome 浏览器中进行本地调试。</p><ol><li><p>在 Chrome 浏览器地址栏输入扩展程序管理地址：<code>chrome://extensions/</code><img src="'+c+'" alt="打开 Chrome 扩展程序管理界面"></p></li><li><p>确保页面右上角的 <strong>开发者模式 (Developer mode)</strong> 处于开启状态。</p></li><li><p>点击左上角的 <strong>加载已解压的扩展程序 (Load unpacked)</strong>。 <img src="'+n+'" alt="点击加载已解压的扩展程序"></p></li><li><p>在弹出的本地文件选择窗口中，选中您的插件所在目录（例如 <code>practice/table-exporter/</code> 或 <code>demo/logistics-table-tool/</code>）。</p></li><li><p>载入成功后，您的扩展面板中将展示出“数字叉车”或“Web 表格导出工具”的卡片，代表插件已就绪。 <img src="'+l+'" alt="插件载入成功"></p></li><li><p><em>(可选)</em> 您可以点击浏览器右上角的拼图图标，将该插件“固定”到工具栏，方便观察其状态。 <img src="'+i+'" alt="固定插件到工具栏"></p></li></ol><hr><h2 id="📊-第三步-实地测试与使用-使用" tabindex="-1">📊 第三步：实地测试与使用 (使用) <a class="header-anchor" href="#📊-第三步-实地测试与使用-使用" aria-label="Permalink to &quot;📊 第三步：实地测试与使用 (使用)&quot;">​</a></h2><p>插件载入后，它会在后台静默待命。让我们找一个存在大量表格数据的物流知识库页面进行测试。</p><ol><li><p><strong>进入目标测试页面：</strong> 比如访问我们的运去哪 WMS 知识库进行测试：<a href="https://wms.yqn.com/62102/knowledge?source=%E7%9F%A5%E8%AF%86%E5%BA%93" target="_blank" rel="noreferrer">https://wms.yqn.com/62102/knowledge?source=知识库</a><img src="'+p+'" alt="访问目标知识库页面"></p></li><li><p><strong>自动注入工具栏：</strong> 插件的 <code>content.js</code> 会自动扫描此网页中的 <code>&lt;table&gt;</code> 标签。在页面表格边缘（右上角），您将看到自动弹出的 <strong>导出 CSV</strong> 与 <strong>关闭</strong> 辅助按钮。如果您觉得干扰业务流，可以随时点击“关闭”暂时藏匿。 <img src="'+d+'" alt="表格上方浮现导出按钮"></p></li><li><p><strong>一键提取与下载：</strong> 点击 <strong>导出 CSV</strong>。插件将立即把表格内的数据打包成结构化的文件格式（包含 UTF-8 BOM 防止乱码），并无缝触发自动下载。您可以看到浏览器下载了一份带有当天日期的 <code>.csv</code> 数据报表。 下载的文件您可以直接使用 Excel 打开或导入，当然文本编辑器也可以秒开，非常规整。 <img src="'+m+'" alt="成功导出 CSV 并打开核对"></p></li></ol><blockquote><p><strong>🎉 恭喜！您已经成功掌握了利用 AI 辅助生成的专属物流浏览器插件的工作流。</strong></p></blockquote>',17)])])}const x=o(h,[["render",g]]);export{f as __pageData,x as default};
